app = Flask(__name__)

redis_client = redis.Redis(host="localhost", port=6379, db=0, decode_responses=True)


def cache(ttl=60):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"cache:{func.__name__}:{request.path}:{request.query_string.decode('utf-8')}"
            cached_value = redis_client.get(cache_key)
            if cached_value is not None:
                return jsonify(json.loads(cached_value))

            result = func(*args, **kwargs)
            if isinstance(result, tuple):
                response_body, status_code = result
            else:
                response_body, status_code = result, 200

            try:
                redis_client.setex(cache_key, ttl, json.dumps(response_body))
            except Exception:
                pass

            return make_response(jsonify(response_body), status_code)

        return wrapper
    return decorator


def create_session(user_id, data=None, ttl=3600):
    session_id = str(uuid.uuid4())
    payload = {
        "user_id": user_id,
        "data": data or {},
        "created_at": int(time.time())
    }
    redis_client.setex(f"session:{session_id}", ttl, json.dumps(payload))
    return session_id


def get_session(session_id):
    session_data = redis_client.get(f"session:{session_id}")
    if not session_data:
        return None
    return json.loads(session_data)


def update_session(session_id, updates, ttl=3600):
    current = get_session(session_id)
    if not current:
        return False
    current["data"].update(updates or {})
    redis_client.setex(f"session:{session_id}", ttl, json.dumps(current))
    return True


def delete_session(session_id):
    return redis_client.delete(f"session:{session_id}") > 0


@app.route("/login", methods=["POST"])
def login():
    payload = request.get_json(silent=True) or {}
    user_id = payload.get("user_id")
    if not user_id:
        return jsonify({"error": "user_id is required"}), 400

    session_id = create_session(user_id, data=payload.get("data", {}))
    response = jsonify({"message": "logged in", "session_id": session_id})
    response.set_cookie("session_id", session_id, httponly=True, samesite="Lax")
    return response, 200


